272	// ParseIdentity parses component c with path s into a StringIdentity.
273	func (pp *PathParser) ParseIdentity(c, s string) identity.StringIdentity {
274		p := pp.parsePooled(c, s)
275		defer putPath(p)
276		return identity.StringIdentity(p.IdentifierBase())
277	}
