279	// ParseBaseAndBaseNameNoIdentifier parses component c with path s into a base and a base name without any identifier.
280	func (pp *PathParser) ParseBaseAndBaseNameNoIdentifier(c, s string) (string, string) {
281		p := pp.parsePooled(c, s)
282		defer putPath(p)
283		return p.Base(), p.BaseNameNoIdentifier()
284	}
285	
286	func (pp *PathParser) parsePooled(c, s string) *Path {
287		s = NormalizePathStringBasic(s)
288		p := getPath()
289		p.component = c
290		p, err := pp.doParse(c, s, p)
291		if err != nil {
292			panic(err)
293		}
294		return p
295	}
296	
297	// Parse parses component c with path s into Path using Hugo's content path rules.
298	func (pp *PathParser) Parse(c, s string) *Path {
299		p, err := pp.parse(c, s)
300		if err != nil {
301			panic(err)
302		}
303		return p
304	}
