306	func (pp *PathParser) newPath(component string) *Path {
307		p := &Path{}
308		p.reset()
309		p.component = component
310		return p
311	}
312	
313	func (pp *PathParser) parse(component, s string) (*Path, error) {
314		ss := NormalizePathStringBasic(s)
315	
316		p, err := pp.doParse(component, ss, pp.newPath(component))
317		if err != nil {
318			return nil, err
319		}
320	
321		if s != ss {
322			var err error
323			// Preserve the original case for titles etc.
324			p.unnormalized, err = pp.doParse(component, s, pp.newPath(component))
325			if err != nil {
326				return nil, err
327			}
328		} else {
329			p.unnormalized = p
330		}
331	
332		return p, nil
333	}
