592	//go:generate stringer -type Type
593	
594	type Type int
595	
596	const (
597	
598		// A generic file, e.g. a JSON file.
599		TypeFile Type = iota
600	
601		// All below are content files.
602		// A resource of a content type with front matter.
603		TypeContentResource
604	
605		// E.g. /blog/my-post.md
606		TypeContentSingle
607	
608		// All below are bundled content files.
609	
610		// Leaf bundles, e.g. /blog/my-post/index.md
611		TypeLeaf
612	
613		// Branch bundles, e.g. /blog/_index.md
614		TypeBranch
615	
616		// Content data file, _content.gotmpl.
617		TypeContentData
618	
619		// Layout types.
620		TypeMarkup
621		TypeShortcode
622		TypePartial
623		TypeBaseof
624	)
625	
626	type Path struct {
627		// Note: Any additions to this struct should also be added to the pathPool.
628		s string
629	
630		posContainerLow  int
631		posContainerHigh int
632		posSectionHigh   int
633	
634		component string
635		pathType  Type
636	
637		identifiersKnown   []types.LowHigh[string]
638		identifiersUnknown []types.LowHigh[string]
639	
640		posIdentifierLanguage     int
641		posIdentifierOutputFormat int
642		posIdentifierKind         int
643		posIdentifierLayout       int
644		posIdentifierBaseof       int
645		posIdentifierCustom       int
646	
647		// Prefix identifier positions (indices into identifiersKnown).
648		posIdentifierPrefixLanguages    []int
649		posIdentifierVersions           []int
650		posIdentifierRoles              []int
651		posIdentifierPrefixOutputFormat int
652		posIdentifierPrefixKind         int
653		posIdentifierPrefixLayout       int
654	
655		// Name boundary, computed during parse.
656		posIdentifierName types.LowHigh[string]
657		// Position of the dot before the leftmost known identifier.
658		// Set during parseIdentifier, used to compute posIdentifierName.
659		posNameHigh int
660	
661		disabled bool
662	
663		trimLeadingSlash bool
664	
665		unnormalized *Path
666	}
667	
668	var pathPool = &sync.Pool{
669		New: func() any {
670			p := &Path{}
671			p.reset()
672			return p
673		},
674	}
675	
676	func getPath() *Path {
677		return pathPool.Get().(*Path)
