128	func DecodeCascadeConfig(in any) (*PageMatcherParamsConfigs, error) {
129		buildConfig := func(in any) (CascadeConfig, any, error) {
130			dec := cascadeConfigDecoder{}
131	
132			if in == nil {
133				return CascadeConfig{}, []map[string]any{}, nil
134			}
135	
136			ms, err := hmaps.ToSliceStringMap(in)
137			if err != nil {
