141			var cfgs []PageMatcherParamsConfig
142	
143			for _, m := range ms {
144				m = hmaps.CleanConfigStringMap(m)
145				var (
146					c   PageMatcherParamsConfig
147					err error
148				)
149				c, err = dec.mapToPageMatcherParamsConfig(m)
150				if err != nil {
151					return CascadeConfig{}, nil, err
152				}
153				for k := range m {
154					if disallowedCascadeKeys[k] {
155						return CascadeConfig{}, nil, fmt.Errorf("key %q not allowed in cascade config", k)
156					}
157				}
158				cfgs = append(cfgs, c)
159			}
160	
161			if len(cfgs) == 0 {
162				return CascadeConfig{}, nil, nil
163			}
164	
165			var n int
166			for _, cfg := range cfgs {
167				if len(cfg.Params) > 0 || len(cfg.Fields) > 0 {
168					cfgs[n] = cfg
169					n++
170				}
171			}
