192	func (d cascadeConfigDecoder) mapToPageMatcherParamsConfig(m map[string]any) (PageMatcherParamsConfig, error) {
193		var pcfg PageMatcherParamsConfig
194		if pcfg.Fields == nil {
195			pcfg.Fields = make(hmaps.Params)
