253	func (v *PageMatcher) compileSitesMatrix(defaults sitesmatrix.VectorStore, configuredDimensions *sitesmatrix.ConfiguredDimensions) error {
254		if v.Sites.Matrix.IsZero() && defaults == nil {
255			// Nothing to do.
256			v.SitesMatrixCompiled = nil
257			return nil
258		}
259		intSetsCfg := sitesmatrix.IntSetsConfig{
260			Globs: v.Sites.Matrix,
261		}
262	
263		b := sitesmatrix.NewIntSetsBuilder(configuredDimensions).WithConfig(intSetsCfg)
264		if defaults != nil && v.Sites.Matrix.IsZero() {
265			b = b.WithDimensionsFromOtherIfNotSet(defaults)
266		}
267		b = b.WithAllIfNotSet()
268		v.SitesMatrixCompiled = b.Build()
269		return nil
