327	func (c *PageMatcherParamsConfigs) All() iter.Seq[PageMatcherParamsConfig] {
328		if c == nil {
329			return func(func(PageMatcherParamsConfig) bool) {}
330		}
331		return func(yield func(PageMatcherParamsConfig) bool) {
332			if c == nil {
333				return
334			}
335			for _, v := range c.c {
336				for _, vv := range v.Config.Cascades {
337					if !yield(vv) {
338						return
339					}
340				}
341			}
342		}
343	}
