356	func (c *PageMatcherParamsConfigs) SourceHash() uint64 {
357		if c == nil {
358			return 0
359		}
360		h := hashing.XxHasher()
361		defer h.Close()
362	
363		for _, v := range c.c {
364			h.WriteString(v.SourceHash)
365		}
366		return h.Sum64()
367	}
