369	func (c *PageMatcherParamsConfigs) InitConfig(logger loggers.Logger, defaultsIn sitesmatrix.VectorStore, configuredDimensions *sitesmatrix.ConfiguredDimensions) error {
370		if c == nil {
371			return nil
372		}
373		for _, cc := range c.c {
