382				if err := ccc.Target.compileSitesMatrix(defaults, configuredDimensions); err != nil {
383					return fmt.Errorf("failed to compile cascade target %d: %w", i, err)
384				}
385				cc.Config.Cascades[i] = ccc
386			}
387		}
388		return nil
