230	// SourceFilesystems contains the different source file systems. These can be
231	// composite file systems (theme and project etc.), and they have all root
232	// set to the source type the provides: data, i18n, static, layouts.
233	type SourceFilesystems struct {
234		Content    *SourceFilesystem
235		Data       *SourceFilesystem
236		I18n       *SourceFilesystem
237		Layouts    *SourceFilesystem
238		Archetypes *SourceFilesystem
239		Assets     *SourceFilesystem
240	
241		AssetsWithDuplicatesPreserved *SourceFilesystem
242	
243		RootFss []*hugofs.RootMappingFs
244	
245		// Writable filesystem on top the project's resources directory,
246		// with any sub module's resource fs layered below.
247		ResourcesCache afero.Fs
248	
249		// The work folder (may be a composite of project and theme components).
250		Work afero.Fs
251	
252		// When in multihost we have one static filesystem per language. The sync
253		// static files is currently done outside of the Hugo build (where there is
254		// a concept of a site per language).
255		// When in non-multihost mode there will be one entry in this map with a blank key.
256		Static map[string]*SourceFilesystem
257	
258		conf config.AllProvider
259	}
260	
261	// A SourceFilesystem holds the filesystem for a given source type in Hugo (data,
262	// i18n, layouts, static) and additional metadata to be able to use that filesystem
263	// in server mode.
264	type SourceFilesystem struct {
265		// Name matches one in files.ComponentFolders
266		Name string
267	
268		// This is a virtual composite filesystem. It expects path relative to a context.
269		Fs afero.Fs
270	
271		// The source filesystem (usually the OS filesystem).
272		SourceFs afero.Fs
273	
274		// When syncing a source folder to the target (e.g. /public), this may
275		// be set to publish into a subfolder. This is used for static syncing
276		// in multihost mode.
277		PublishFolder string
278	}
279	
280	// StaticFs returns the static filesystem for the given language.
281	// This can be a composite filesystem.
282	func (s SourceFilesystems) StaticFs(lang string) afero.Fs {
283		var staticFs afero.Fs = hugofs.NoOpFs
284	
285		if fs, ok := s.Static[lang]; ok {
286			staticFs = fs.Fs
287		} else if fs, ok := s.Static[""]; ok {
288			staticFs = fs.Fs
289		}
290	
291		return staticFs
292	}
293	
294	// StatResource looks for a resource in these filesystems in order: static, assets and finally content.
295	// If found in any of them, it returns FileInfo and the relevant filesystem.
296	// Any non herrors.IsNotExist error will be returned.
297	// An herrors.IsNotExist error will be returned only if all filesystems return such an error.
298	// Note that if we only wanted to find the file, we could create a composite Afero fs,
299	// but we also need to know which filesystem root it lives in.
300	func (s SourceFilesystems) StatResource(lang, filename string) (fi os.FileInfo, fs afero.Fs, err error) {
301		for _, fsToCheck := range []afero.Fs{s.StaticFs(lang), s.Assets.Fs, s.Content.Fs} {
302			fs = fsToCheck
303			fi, err = fs.Stat(filename)
304			if err == nil || !herrors.IsNotExist(err) {
305				return
306			}
307		}
308		// Not found.
309		return
310	}
311	
312	// IsStatic returns true if the given filename is a member of one of the static
313	// filesystems.
314	func (s SourceFilesystems) IsStatic(filename string) bool {
315		for _, staticFs := range s.Static {
316			if staticFs.Contains(filename) {
317				return true
318			}
319		}
320		return false
321	}
322	
323	// IsContent returns true if the given filename is a member of the content filesystem.
324	func (s SourceFilesystems) IsContent(filename string) bool {
325		return s.Content.Contains(filename)
326	}
327	
328	// ResolvePaths resolves the given filename to a list of paths in the filesystems.
329	func (s *SourceFilesystems) ResolvePaths(filename string) []hugofs.ComponentPath {
330		var cpss []hugofs.ComponentPath
331		for _, rfs := range s.RootFss {
332			cps, err := rfs.ReverseLookup(filename)
333			if err != nil {
334				panic(err)
335			}
336			cpss = append(cpss, cps...)
337		}
338		return cpss
339	}
340	
341	// MakeStaticPathRelative makes an absolute static filename into a relative one.
342	// It will return an empty string if the filename is not a member of a static filesystem.
343	func (s SourceFilesystems) MakeStaticPathRelative(filename string) string {
344		for _, staticFs := range s.Static {
345			rel, _ := staticFs.MakePathRelative(filename, true)
346			if rel != "" {
347				return rel
348			}
349		}
350		return ""
351	}
352	
353	// MakePathRelative creates a relative path from the given filename.
354	func (d *SourceFilesystem) MakePathRelative(filename string, checkExists bool) (string, bool) {
355		cps, err := d.ReverseLookup(filename, checkExists)
356		if err != nil {
357			panic(err)
358		}
359		if len(cps) == 0 {
360			return "", false
361		}
362	
363		return filepath.FromSlash(cps[0].Path), true
364	}
365	
366	// ReverseLookup returns the component paths for the given filename.
367	func (d *SourceFilesystem) ReverseLookup(filename string, checkExists bool) ([]hugofs.ComponentPath, error) {
368		var cps []hugofs.ComponentPath
369		hugofs.WalkFilesystems(d.Fs, func(fs afero.Fs) bool {
370			if rfs, ok := fs.(hugofs.ReverseLookupProvder); ok {
371				if c, err := rfs.ReverseLookupComponent(d.Name, filename); err == nil {
372					if checkExists {
373						n := 0
374						for _, cp := range c {
375							if _, err := d.Fs.Stat(filepath.FromSlash(cp.Path)); err == nil {
376								c[n] = cp
377								n++
378							}
379						}
380						c = c[:n]
381					}
382					cps = append(cps, c...)
383				}
384			}
385			return false
386		})
387		return cps, nil
388	}
389	
390	func (d *SourceFilesystem) mounts() []hugofs.FileMetaInfo {
391		var m []hugofs.FileMetaInfo
392		hugofs.WalkFilesystems(d.Fs, func(fs afero.Fs) bool {
393			if rfs, ok := fs.(*hugofs.RootMappingFs); ok {
394				mounts, err := rfs.Mounts(d.Name)
395				if err == nil {
396					m = append(m, mounts...)
397				}
398			}
399			return false
400		})
401	
402		// Filter out any mounts not belonging to this filesystem.
403		// TODO(bep) I think this is superfluous.
404		n := 0
405		for _, mm := range m {
406			if mm.Meta().Component == d.Name {
407				m[n] = mm
408				n++
409			}
410		}
411		m = m[:n]
412	
413		return m
414	}
415	
416	func (d *SourceFilesystem) RealFilename(rel string) string {
417		fi, err := d.Fs.Stat(rel)
418		if err != nil {
419			return rel
420		}
421		if realfi, ok := fi.(hugofs.FileMetaInfo); ok {
422			return realfi.Meta().Filename
423		}
424	
425		return rel
426	}
427	
428	// Contains returns whether the given filename is a member of the current filesystem.
429	func (d *SourceFilesystem) Contains(filename string) bool {
430		for _, dir := range d.mounts() {
431			if !dir.IsDir() {
432				continue
433			}
434			if strings.HasPrefix(filename, dir.Meta().Filename) {
435				return true
436			}
437		}
438		return false
439	}
440	
441	// RealDirs gets a list of absolute paths to directories starting from the given
442	// path.
443	func (d *SourceFilesystem) RealDirs(from string) []string {
444		var dirnames []string
445		for _, m := range d.mounts() {
446			if !m.IsDir() {
447				continue
448			}
449			dirname := filepath.Join(m.Meta().Filename, from)
450			if _, err := d.SourceFs.Stat(dirname); err == nil {
451				dirnames = append(dirnames, dirname)
452			}
453		}
454		return dirnames
455	}
456	
457	// WithBaseFs allows reuse of some potentially expensive to create parts that remain
458	// the same across sites/languages.
459	func WithBaseFs(b *BaseFs) func(*BaseFs) error {
460		return func(bb *BaseFs) error {
461			bb.theBigFs = b.theBigFs
462			bb.SourceFilesystems = b.SourceFilesystems
463			return nil
464		}
465	}
466	
467	// NewBase builds the filesystems used by Hugo given the paths and options provided.NewBase
468	func NewBase(p *paths.Paths, logger loggers.Logger, options ...func(*BaseFs) error) (*BaseFs, error) {
469		fs := p.Fs
470		if logger == nil {
471			logger = loggers.NewDefault()
472		}
473	
474		publishFs := hugofs.NewBaseFileDecorator(fs.PublishDir)
475		projectSourceFs := hugofs.NewBaseFileDecorator(hugofs.NewBasePathFs(fs.Source, p.Cfg.BaseConfig().WorkingDir))
476		sourceFs := hugofs.NewBaseFileDecorator(fs.Source)
477		publishFsStatic := fs.PublishDirStatic
478	
479		var buildMu Lockable
480		if p.Cfg.NoBuildLock() || htesting.IsTest {
481			buildMu = &fakeLockfileMutex{}
482		} else {
483			buildMu = lockedfile.MutexAt(filepath.Join(p.Cfg.BaseConfig().WorkingDir, lockFileBuild))
484		}
485	
486		b := &BaseFs{
487			SourceFs:        sourceFs,
488			ProjectSourceFs: projectSourceFs,
489			WorkDir:         fs.WorkingDirReadOnly,
490			PublishFs:       publishFs,
491			PublishFsStatic: publishFsStatic,
492			workingDir:      p.Cfg.BaseConfig().WorkingDir,
493			buildMu:         buildMu,
494		}
495	
496		for _, opt := range options {
497			if err := opt(b); err != nil {
498				return nil, err
499			}
500		}
501	
502		if b.theBigFs != nil && b.SourceFilesystems != nil {
503			return b, nil
504		}
505	
506		builder := newSourceFilesystemsBuilder(p, logger, b)
507		sourceFilesystems, err := builder.Build()
508		if err != nil {
509			return nil, fmt.Errorf("build filesystems: %w", err)
510		}
511	
512		b.SourceFilesystems = sourceFilesystems
513		b.theBigFs = builder.theBigFs
514	
515		return b, nil
516	}
517	
518	type sourceFilesystemsBuilder struct {
519		logger   loggers.Logger
520		p        *paths.Paths
521		sourceFs afero.Fs
522		result   *SourceFilesystems
523		theBigFs *filesystemsCollector
524	}
525	
526	func newSourceFilesystemsBuilder(p *paths.Paths, logger loggers.Logger, b *BaseFs) *sourceFilesystemsBuilder {
527		sourceFs := hugofs.NewBaseFileDecorator(p.Fs.Source)
528		return &sourceFilesystemsBuilder{
529			p: p, logger: logger, sourceFs: sourceFs, theBigFs: b.theBigFs,
530			result: &SourceFilesystems{
531				conf: p.Cfg,
532			},
533		}
534	}
535	
536	func (b *sourceFilesystemsBuilder) newSourceFilesystem(name string, fs afero.Fs) *SourceFilesystem {
537		return &SourceFilesystem{
538			Name:     name,
539			Fs:       fs,
540			SourceFs: b.sourceFs,
541		}
542	}
543	
544	func (b *sourceFilesystemsBuilder) Build() (*SourceFilesystems, error) {
545		if b.theBigFs == nil {
546			theBigFs, err := b.createMainOverlayFs(b.p)
547			if err != nil {
548				return nil, fmt.Errorf("create main fs: %w", err)
549			}
550	
551			b.theBigFs = theBigFs
552		}
553	
554		createView := func(componentID string, overlayFs *overlayfs.OverlayFs) *SourceFilesystem {
555			if b.theBigFs == nil || b.theBigFs.overlayMounts == nil {
556				return b.newSourceFilesystem(componentID, hugofs.NoOpFs)
557			}
558	
559			fs := hugofs.NewComponentFs(
560				hugofs.ComponentFsOptions{
561					Fs:        overlayFs,
562					Component: componentID,
563					Cfg:       b.p.Cfg,
564				},
565			)
566	
567			return b.newSourceFilesystem(componentID, fs)
568		}
569	
570		b.result.Archetypes = createView(files.ComponentFolderArchetypes, b.theBigFs.overlayMounts)
571		b.result.Layouts = createView(files.ComponentFolderLayouts, b.theBigFs.overlayMounts)
572		b.result.Assets = createView(files.ComponentFolderAssets, b.theBigFs.overlayMounts)
573		b.result.ResourcesCache = b.theBigFs.overlayResources
574		b.result.RootFss = b.theBigFs.rootFss
575	
576		// data and i18n  needs a different merge strategy.
577		overlayMountsPreserveDupes := b.theBigFs.overlayMounts.WithDirsMerger(hugofs.AppendDirsMerger)
578		b.result.Data = createView(files.ComponentFolderData, overlayMountsPreserveDupes)
579		b.result.I18n = createView(files.ComponentFolderI18n, overlayMountsPreserveDupes)
580		b.result.AssetsWithDuplicatesPreserved = createView(files.ComponentFolderAssets, overlayMountsPreserveDupes)
581	
582		contentFs := hugofs.NewComponentFs(
583			hugofs.ComponentFsOptions{
584				Fs:        b.theBigFs.overlayMountsContent,
585				Component: files.ComponentFolderContent,
586				Cfg:       b.p.Cfg,
587			},
588		)
589	
590		b.result.Content = b.newSourceFilesystem(files.ComponentFolderContent, contentFs)
591		b.result.Work = hugofs.NewReadOnlyFs(b.theBigFs.overlayFull)
592	
593		// Create static filesystem(s)
594		ms := make(map[string]*SourceFilesystem)
595		b.result.Static = ms
596	
597		if b.theBigFs.staticPerLanguage != nil {
598			// Multihost mode
599			for k, v := range b.theBigFs.staticPerLanguage {
600				sfs := b.newSourceFilesystem(files.ComponentFolderStatic, v)
601				sfs.PublishFolder = k
602				ms[k] = sfs
603			}
604		} else {
605			bfs := hugofs.NewBasePathFs(b.theBigFs.overlayMountsStatic, files.ComponentFolderStatic)
606			ms[""] = b.newSourceFilesystem(files.ComponentFolderStatic, bfs)
607		}
608	
609		return b.result, nil
610	}
611	
612	func (b *sourceFilesystemsBuilder) createMainOverlayFs(p *paths.Paths) (*filesystemsCollector, error) {
613		var staticFsMap map[string]*overlayfs.OverlayFs
614		if b.p.Cfg.IsMultihost() {
615			languages := b.p.Cfg.Languages().(langs.Languages)
616			staticFsMap = make(map[string]*overlayfs.OverlayFs)
617			for _, l := range languages {
618				staticFsMap[l.Lang] = overlayfs.New(overlayfs.Options{})
619			}
620		}
621	
622		collector := &filesystemsCollector{
623			sourceProject:     b.sourceFs,
624			sourceModules:     b.sourceFs,
625			staticPerLanguage: staticFsMap,
626	
627			overlayMounts:        overlayfs.New(overlayfs.Options{}),
628			overlayMountsContent: overlayfs.New(overlayfs.Options{DirsMerger: hugofs.AppendDirsMerger}),
629			overlayMountsStatic:  overlayfs.New(overlayfs.Options{}),
630			overlayFull:          overlayfs.New(overlayfs.Options{}),
631			overlayResources:     overlayfs.New(overlayfs.Options{FirstWritable: true}),
632		}
633	
634		mods := p.AllModules()
635	
636		mounts := make([]mountsDescriptor, len(mods))
637	
638		for i := range mods {
639			mod := mods[i]
640			dir := mod.Dir()
641	
642			isMainProject := mod.Owner() == nil
643			mounts[i] = mountsDescriptor{
644				Module:        mod,
645				dir:           dir,
646				isMainProject: isMainProject,
647				ordinal:       i,
648			}
649	
650		}
651	
652		err := b.createOverlayFs(collector, mounts)
653	
654		return collector, err
655	}
656	
657	func (b *sourceFilesystemsBuilder) isContentMount(mnt modules.Mount) bool {
658		return strings.HasPrefix(mnt.Target, files.ComponentFolderContent)
659	}
660	
661	func (b *sourceFilesystemsBuilder) isStaticMount(mnt modules.Mount) bool {
662		return strings.HasPrefix(mnt.Target, files.ComponentFolderStatic)
663	}
664	
665	func (b *sourceFilesystemsBuilder) isLayoutsMount(mnt modules.Mount) bool {
666		return strings.HasPrefix(mnt.Target, files.ComponentFolderLayouts)
667	}
668	
669	func (b *sourceFilesystemsBuilder) createOverlayFs(
670		collector *filesystemsCollector,
671		mounts []mountsDescriptor,
672	) error {
673		if len(mounts) == 0 {
674			appendNopIfEmpty := func(ofs *overlayfs.OverlayFs) *overlayfs.OverlayFs {
675				if ofs.NumFilesystems() > 0 {
676					return ofs
677				}
678				return ofs.Append(hugofs.NoOpFs)
679			}
680			collector.overlayMounts = appendNopIfEmpty(collector.overlayMounts)
681			collector.overlayMountsContent = appendNopIfEmpty(collector.overlayMountsContent)
682			collector.overlayMountsStatic = appendNopIfEmpty(collector.overlayMountsStatic)
683			collector.overlayMountsFull = appendNopIfEmpty(collector.overlayMountsFull)
684			collector.overlayFull = appendNopIfEmpty(collector.overlayFull)
685			collector.overlayResources = appendNopIfEmpty(collector.overlayResources)
686	
687			return nil
688		}
689	
690		for _, md := range mounts {
691			var (
692				fromTo        []*hugofs.RootMapping
693				fromToContent []*hugofs.RootMapping
694				fromToStatic  []*hugofs.RootMapping
695			)
696	
697			absPathify := func(path string) (string, string) {
698				if filepath.IsAbs(path) {
699					return "", path
700				}
701				return md.dir, hpaths.AbsPathify(md.dir, path)
702			}
703	
704			for i, mount := range md.Mounts() {
705				// Add more weight to early mounts.
706				// When two mounts contain the same filename,
707				// the first entry wins.
708				mountWeight := (10 + md.ordinal) * (len(md.Mounts()) - i)
709	
710				patterns, hasLegacyIncludes, hasLegacyExcludes := mount.FilesToFilter()
711				if hasLegacyIncludes {
712					hugo.Deprecate("module.mounts.includeFiles", "Replaced by the simpler 'files' setting, see https://gohugo.io/configuration/module/#files", "v0.153.0")
713				}
714				if hasLegacyExcludes {
715					hugo.Deprecate("module.mounts.excludeFiles", "Replaced by the simpler 'files' setting, see https://gohugo.io/configuration/module/#files", "v0.153.0")
716				}
717	
718				inclusionFilter, err := hglob.NewFilenameFilterV2(patterns)
719				if err != nil {
720					return err
721				}
722	
723				base, filename := absPathify(mount.Source)
724	
725				var matrix *sitesmatrix.IntSets
726				v := mount.Sites
727	
728				needsDefaultsIfNotset := b.isContentMount(mount)
729				needsDefaultsAndAllLanguagesIfNotSet := b.isStaticMount(mount)
730				needsAllIfNotSet := b.isLayoutsMount(mount)
731	
732				intSetsCfg := sitesmatrix.IntSetsConfig{
733					ApplyDefaults: 0,
734					Globs:         v.Matrix,
735				}
736	
737				matrixBuilder := sitesmatrix.NewIntSetsBuilder(b.p.Cfg.ConfiguredDimensions())
738	
739				if !v.Matrix.IsZero() {
740					matrixBuilder.WithConfig(intSetsCfg)
741					if !matrixBuilder.GlobFilterMisses.IsZero() {
742						continue
743					}
744	
745					if needsDefaultsIfNotset {
746						matrixBuilder.WithDefaultsIfNotSet()
747					}
748					if needsAllIfNotSet {
749						matrixBuilder.WithAllIfNotSet()
750					}
751	
752					matrix = matrixBuilder.Build()
753				} else if needsAllIfNotSet {
754					matrixBuilder.WithAllIfNotSet()
755					matrix = matrixBuilder.Build()
756				} else if needsDefaultsAndAllLanguagesIfNotSet {
757					matrixBuilder.WithDefaultsAndAllLanguagesIfNotSet()
758					matrix = matrixBuilder.Build()
759				} else if needsDefaultsIfNotset {
760					matrix = b.p.Cfg.DefaultContentsitesMatrix()
761				} else {
762					if needsDefaultsIfNotset {
763						matrixBuilder.WithDefaultsIfNotSet()
764					}
765					matrix = matrixBuilder.Build()
766				}
767	
768				var complements *sitesmatrix.IntSets
769				if !v.Complements.IsZero() {
770					intSetsCfg.Globs = v.Complements
771					intSetsCfg.ApplyDefaults = 0
772					matrixBuilder = sitesmatrix.NewIntSetsBuilder(b.p.Cfg.ConfiguredDimensions()).WithConfig(intSetsCfg).WithAllIfNotSet()
773					complements = matrixBuilder.Build()
774				}
775	
776				rm := &hugofs.RootMapping{
777					From:          mount.Target,
778					To:            filename,
779					ToBase:        base,
780					Module:        md.Module,
781					ModuleOrdinal: md.ordinal,
782					IsProject:     md.isMainProject,
783					Meta: &hugofs.FileMeta{
784						Watch:            !mount.DisableWatch && md.Watch(),
785						Weight:           mountWeight,
786						InclusionFilter:  inclusionFilter,
787						SitesMatrix:      matrix,
788						SitesComplements: complements,
789					},
790				}
791	
792				isContentMount := b.isContentMount(mount)
793	
794				if isContentMount {
795					fromToContent = append(fromToContent, rm)
796				} else if b.isStaticMount(mount) {
797					fromToStatic = append(fromToStatic, rm)
798				} else {
799					fromTo = append(fromTo, rm)
800				}
801			}
802	
803			modBase := collector.sourceProject
804			if !md.isMainProject {
805				modBase = collector.sourceModules
806			}
807	
808			sourceStatic := modBase
809	
810			rmfs, err := hugofs.NewRootMappingFs(modBase, fromTo...)
811			if err != nil {
812				return err
813			}
814			rmfsContent, err := hugofs.NewRootMappingFs(modBase, fromToContent...)
815			if err != nil {
816				return err
817			}
818			rmfsStatic, err := hugofs.NewRootMappingFs(sourceStatic, fromToStatic...)
819			if err != nil {
820				return err
821			}
822	
823			// We need to keep the list of directories for watching.
824			collector.addRootFs(rmfs)
825			collector.addRootFs(rmfsContent)
826			collector.addRootFs(rmfsStatic)
827	
828			if collector.staticPerLanguage != nil {
829				for i, l := range b.p.Cfg.Languages().(langs.Languages) {
830					lang := l.Lang
831	
832					lfs := rmfsStatic.Filter(func(rm *hugofs.RootMapping) bool {
833						return rm.Meta.SitesMatrix.HasLanguage(i)
834					})
835					bfs := hugofs.NewBasePathFs(lfs, files.ComponentFolderStatic)
836					collector.staticPerLanguage[lang] = collector.staticPerLanguage[lang].Append(bfs)
837				}
838			}
839	
840			getResourcesDir := func() string {
841				if md.isMainProject {
842					return b.p.AbsResourcesDir
843				}
844				_, filename := absPathify(files.FolderResources)
845				return filename
846			}
847	
848			collector.overlayMounts = collector.overlayMounts.Append(rmfs)
849			collector.overlayMountsContent = collector.overlayMountsContent.Append(rmfsContent)
850			collector.overlayMountsStatic = collector.overlayMountsStatic.Append(rmfsStatic)
851			collector.overlayFull = collector.overlayFull.Append(hugofs.NewBasePathFs(modBase, md.dir))
852			collector.overlayResources = collector.overlayResources.Append(hugofs.NewBasePathFs(modBase, getResourcesDir()))
853	
854		}
855	
856		return nil
857	}
858	
859	//lint:ignore U1000 useful for debugging
860	func printFs(fs afero.Fs, path string, w io.Writer) {
861		if fs == nil {
862			return
863		}
864		afero.Walk(fs, path, func(path string, info os.FileInfo, err error) error {
865			if err != nil {
866				return err
867			}
868			if info.IsDir() {
869				return nil
870			}
871			var filename string
872			if fim, ok := info.(hugofs.FileMetaInfo); ok {
873				filename = fim.Meta().Filename
874			}
875			fmt.Fprintf(w, "    %q %q\n", path, filename)
876			return nil
877		})
878	}
879	
880	type filesystemsCollector struct {
881		sourceProject afero.Fs // Source for project folders
882		sourceModules afero.Fs // Source for modules/themes
883	
884		overlayMounts        *overlayfs.OverlayFs
885		overlayMountsContent *overlayfs.OverlayFs
886		overlayMountsStatic  *overlayfs.OverlayFs
887		overlayMountsFull    *overlayfs.OverlayFs
888		overlayFull          *overlayfs.OverlayFs
889		overlayResources     *overlayfs.OverlayFs
890	
891		rootFss []*hugofs.RootMappingFs
892	
893		// Set if in multihost mode
894		staticPerLanguage map[string]*overlayfs.OverlayFs
895	}
896	
897	func (c *filesystemsCollector) addRootFs(rfs *hugofs.RootMappingFs) {
898		c.rootFss = append(c.rootFss, rfs)
899	}
900	
901	type mountsDescriptor struct {
902		modules.Module
903		dir           string
904		isMainProject bool
905		ordinal       int // zero based starting from the project.
906	}
907	

