222	func (h helperContentNode) findContentNodeForSiteVector(q sitesmatrix.Vector, fallback bool, candidates contentNodeSeq) contentNodeForSite {
223		var (
224			best         contentNodeForSite = nil
225			bestDistance int
226			bestWeight   int
227		)
228	
229		for n := range candidates {
230			// The order of candidates is unstable, so we need to compare the matches to
231			// get stable output. This compare will also make sure that we pick
232			// language, version and role according to their individual sort order:
233			// Closer is better, and matches above are better than matches below.
234			if m := n.(contentNodeLookupContentNodes).lookupContentNodes(q, fallback); m != nil {
235				for nn := range m {
236					vec := nn.siteVector()
237					var w int
238					if wp, ok := nn.(contentNodeContentWeightProvider); ok {
239						w = wp.contentWeight()
240					}
241	
242					if q == vec && w > 0 {
243						// Exact match backed by a file.
244						return nn
245					}
246	
247					distance := q.Distance(vec)
248					distanceAbs := absint(distance)
249	
250					if best == nil {
251						best = nn
252						bestDistance = distance
253						bestWeight = w
254					} else {
255						bestDistanceAbs := absint(bestDistance)
256						if w > 0 && bestWeight == 0 {
257							// Prefer file-backed pages over auto pages.
258							best = nn
259							bestDistance = distance
260							bestWeight = w
261						} else if (w > 0) == (bestWeight > 0) {
262							// Both file-backed or both auto: use distance.
263							if distanceAbs < bestDistanceAbs {
264								best = nn
265								bestDistance = distance
266								bestWeight = w
267							} else if distanceAbs == bestDistanceAbs && distance > 0 {
268								best = nn
269								bestDistance = distance
270								bestWeight = w
271							}
272						}
273					}
274				}
275			}
276		}
