394	// Complement returns a new VectorStore that contains all vectors in s that are not in any of ss.
395	func (s *IntSets) Complement(ss ...VectorProvider) VectorStore {
396		if len(ss) == 0 || (len(ss) == 1 && ss[0] == s) {
397			return NilStore
398		}
399	
400		for _, v := range ss {
401			vv, ok := v.(*IntSets)
402			if !ok {
403				continue
404			}
405			if vv.IsSuperSet(s) {
406				return NilStore
407			}
408		}
409	
410		result := newVectorStoreMap(36)
411	
412		s.ForEachVector(func(vec Vector) bool {
413			var found bool
414			for _, v := range ss {
415				if v.HasVector(vec) {
416					found = true
417					break
418				}
419			}
420	
421			if !found {
422				result.setVector(vec)
423			}
424	
425			return true
426		})
427	
428		return result
429	}
