431	func (s *IntSets) EqualsVector(other VectorProvider) bool {
432		if s == nil && other == nil {
433			return true
434		}
435		if s == nil || other == nil {
436			return false
437		}
438		if s == other {
439			return true
440		}
441		if s.LenVectors() != other.LenVectors() {
442			return false
443		}
444	
445		return other.ForEachVector(func(v Vector) bool {
446			return s.HasVector(v)
447		})
448	}
