555	func (s *IntSets) HasAnyVector(v VectorProvider) bool {
556		if s == nil || v == nil {
557			return false
558		}
559		if s.LenVectors() == 0 || v.LenVectors() == 0 {
560			return false
561		}
562		if v.LenVectors() == 1 {
563			// Fast path.
564			return s.HasVector(v.VectorSample())
565		}
566	
567		if vs, ok := v.(*IntSets); ok {
568			// Fast path.
569			return s.Intersects(vs)
570		}
571	
572		return !v.ForEachVector(func(vec Vector) bool {
573			if s.HasVector(vec) {
574				return false // stop iteration
575			}
576			return true // continue iteration
577		})
578	}
