739	func (b *IntSetsBuilder) WithConfig(cfg IntSetsConfig) *IntSetsBuilder {
740		applyFilter := func(what string, values []string, matcher ConfiguredDimension) (*hmaps.OrderedIntSet, error) {
741			var result *hmaps.OrderedIntSet
742			if len(values) == 0 {
743	
744				if cfg.ApplyDefaults > 0 {
745					result = hmaps.NewOrderedIntSet()
746				}
747				switch cfg.ApplyDefaults {
748				case IntSetsConfigApplyDefaultsIfNotSet:
749					result.Set(matcher.IndexDefault())
750				case IntSetsConfigApplyDefaultsAndAllLanguagesIfNotSet:
751					if what == "languages" {
752						for i := range matcher.ForEachIndex() {
753							result.Set(i)
754						}
755					} else {
756						result.Set(matcher.IndexDefault())
757					}
758				}
759	
760				return result, nil
761			}
762	
763			filter, err := predicate.NewIndexStringPredicateFromGlobsAndRanges(values, matcher.ResolveIndex, hglob.GetGlobDot)
764			if err != nil {
765				return nil, fmt.Errorf("failed to create filter for %s: %w", what, err)
766			}
767			iter, err := matcher.IndexMatch(filter)
768			if err != nil {
769				return nil, fmt.Errorf("failed to match %s %q: %w", what, values, err)
770			}
771			for i := range iter {
772				if result == nil {
773					result = hmaps.NewOrderedIntSet()
774				}
775				result.Set(i)
776			}
777	
778			return result, nil
779		}
780	
781		l, err1 := applyFilter("languages", cfg.Globs.Languages, b.cfg.ConfiguredLanguages)
782		v, err2 := applyFilter("versions", cfg.Globs.Versions, b.cfg.ConfiguredVersions)
783		r, err3 := applyFilter("roles", cfg.Globs.Roles, b.cfg.ConfiguredRoles)
784	
785		if err := cmp.Or(err1, err2, err3); err != nil {
786			panic(fmt.Errorf("failed to apply filters: %w", err))
787		}
788	
789		b.GlobFilterMisses = Bools{
790			len(cfg.Globs.Languages) > 0 && l == nil,
791			len(cfg.Globs.Versions) > 0 && v == nil,
792			len(cfg.Globs.Roles) > 0 && r == nil,
793		}
794	
795		b.s.languages = l
796		b.s.versions = v
797		b.s.roles = r
798	
799		return b
800	}
