922			slices.Equal(d.Roles, other.Roles)
923	}
924	
925	func (d *StringSlices) SetFromParamsIfNotSet(params hmaps.Params) {
926		const (
927			languagesKey = "languages"
928			versionsKey  = "versions"
929			rolesKey     = "roles"
930		)
931	
