933			if v, ok := params[languagesKey]; ok {
934				d.Languages = types.ToStringSlicePreserveString(v)
935			}
936		}
937	
938		if len(d.Versions) == 0 {
939			if v, ok := params[versionsKey]; ok {
940				d.Versions = types.ToStringSlicePreserveString(v)
941			}
942		}
943	
944		if len(d.Roles) == 0 {
945			if v, ok := params[rolesKey]; ok {
946				d.Roles = types.ToStringSlicePreserveString(v)
947			}
948		}
949	}
950	
951	func (d StringSlices) IsZero() bool {
952		return len(d.Languages) == 0 && len(d.Versions) == 0 && len(d.Roles) == 0
953	}
954	
955	// Used in tests.
956	type testDimension struct {
957		names []string
958	}
959	
960	func (m testDimension) Len() int {
961		return len(m.names)
962	}
963	
964	func (m testDimension) IndexDefault() int {
