28	type (
29		Config[T any] struct {
30			// Shifter handles tree transformations.
31			Shifter        Shifter[T]
32			TransformerRaw Transformer[T]
33		}
34	
35		// Shifter handles tree transformations.
36		Shifter[T any] interface {
37			// ForEeachInDimension will call the given function for each value in the given dimension d.
38			// This is typicall used to e.g. walk all language translations of a given node.
39			// If the function returns false, the walk will stop.
40			ForEeachInDimension(n T, vec sitesmatrix.Vector, d int, f func(T) bool)
41	
42			// ForEeachInAllDimensions will call the given function for each value in all dimensions.
43			// If the function returns false, the walk will stop.
44			ForEeachInAllDimensions(n T, f func(T) bool)
45	
46			// Insert inserts new into the tree into the dimension it provides.
47			// It may replace old.
48			// It returns the updated and existing T
49			// and a bool indicating if an existing record is updated.
50			Insert(old, new T) (T, T, bool)
51	
52			// Delete deletes T from the given dimension and returns the deleted T and whether the dimension was deleted and if  it's empty after the delete.
53			Delete(v T, dimension sitesmatrix.Vector) (T, bool, bool)
54	
55			// DeleteFunc deletes nodes in v from the tree where the given function returns true.
56			// It returns true if it's empty after the delete.
57			DeleteFunc(v T, f func(n T) bool) bool
58	
59			// Shift shifts v into the given dimension,
60			// if fallback is true, it will fall back a fallback match if found.
61			// It returns the shifted T and a bool indicating if the shift was successful.
62			Shift(v T, dimension sitesmatrix.Vector, fallback bool) (T, bool)
63		}
64	
65		Transformer[T any] interface {
66			// Append appends vs to t and returns the updated or replaced T and a bool indicating if T was replaced.
67			// Note that t may be the zero value and should be ignored.
68			Append(t T, ts ...T) (T, bool)
69		}
70	)
71	
72	// NodeShiftTree is the root of a tree that can be shaped using the Shape method.
73	// Note that multiplied shapes of the same tree is meant to be used concurrently,
74	// so use the applicable locking when needed.
75	type NodeShiftTree[T any] struct {
76		tree *radix.Tree[T]
77	
78		// [language, version, role].
79		siteVector     sitesmatrix.Vector
80		shifter        Shifter[T]
81		transformerRaw Transformer[T]
82	
83		mu *sync.RWMutex
84	}
85	
86	func New[T any](cfg Config[T]) *NodeShiftTree[T] {
87		if cfg.Shifter == nil {
88			panic("Shifter is required")
89		}
90	
91		return &NodeShiftTree[T]{
92			mu: &sync.RWMutex{},
93	
94			shifter:        cfg.Shifter,
95			transformerRaw: cfg.TransformerRaw,
96			tree:           radix.New[T](),
97		}
98	}
99	
100	// SiteVector returns the site vector of the current dimension.
101	func (r *NodeShiftTree[T]) SiteVector() sitesmatrix.Vector {
102		return r.siteVector
103	}
104	
105	// Delete deletes the node at the given key in the current dimension.
106	func (r *NodeShiftTree[T]) Delete(key string) (T, bool) {
107		return r.delete(key)
108	}
109	
110	// DeleteFuncRaw deletes nodes in the tree at the given key where the given function returns true.
111	// It will delete nodes in all dimensions.
112	func (r *NodeShiftTree[T]) DeleteFuncRaw(key string, f func(T) bool) (T, int) {
113		var count int
114		var lastDeleted T
115	
116		v, ok := r.tree.Get(key)
117		if !ok {
118			return lastDeleted, count
119		}
120	
121		isEmpty := r.shifter.DeleteFunc(v, func(n T) bool {
122			if f(n) {
123				count++
124				lastDeleted = n
125				return true
126			}
127			return false
128		})
129	
130		if isEmpty {
131			r.tree.Delete(key)
132		}
133	
134		return lastDeleted, count
135	}
136	
137	// DeleteRaw deletes the node at the given key without any shifting or transformation.
138	func (r *NodeShiftTree[T]) DeleteRaw(key string) {
139		r.tree.Delete(key)
140	}
141	
142	// DeletePrefix deletes all nodes with the given prefix in the current dimension.
143	func (r *NodeShiftTree[T]) DeletePrefix(prefix string) int {
144		count := 0
145		var keys []string
146		var zero T
147		var walkFn radix.WalkFn[T] = func(key string, value T) (radix.WalkFlag, T, error) {
148			keys = append(keys, key)
149			return radix.WalkContinue, zero, nil
150		}
151		r.tree.WalkPrefix(prefix, walkFn)
152		for _, key := range keys {
153			if _, ok := r.delete(key); ok {
154				count++
155			}
156		}
157		return count
158	}
159	
160	func (r *NodeShiftTree[T]) delete(key string) (T, bool) {
161		var wasDeleted bool
162		var deleted T
163		if v, ok := r.tree.Get(key); ok {
164			var isEmpty bool
165			deleted, wasDeleted, isEmpty = r.shifter.Delete(v, r.siteVector)
166			if isEmpty {
167				r.tree.Delete(key)
168			}
169		}
170		return deleted, wasDeleted
171	}
172	
173	func (t *NodeShiftTree[T]) DeletePrefixRaw(prefix string) int {
174		count := 0
175		var zero T
176		var walkFn radix.WalkFn[T] = func(key string, value T) (radix.WalkFlag, T, error) {
177			if v, ok := t.tree.Delete(key); ok {
178				resource.MarkStale(v)
179				count++
180			}
181			return radix.WalkContinue, zero, nil
182		}
183		t.tree.WalkPrefix(prefix, walkFn)
184	
185		return count
186	}
