package sitesmatrix_test

import (
	"testing"

	"github.com/gohugoio/hugo/hugolib"
)

// TestFilenameRoleOverride verifies that a filename-based role identifier
// (e.g., _role_member_) overrides the mount configuration's role dimension.
// See issue: Language/role/version set in filename should replace mount configuration.
func TestFilenameRoleOverride(t *testing.T) {
	t.Parallel()

	files := `
-- hugo.toml --
disableKinds = ["taxonomy", "term", "rss", "sitemap", "section"]
defaultContentRole = "guest"
defaultContentRoleInSubDir = true
[roles]
[roles.guest]
weight = 100
[roles.member]
weight = 200
[module]
[[module.mounts]]
source = 'content/member'
target = 'content'
[module.mounts.sites.matrix]
roles = "member"
[[module.mounts]]
source = 'content/guest'
target = 'content'
[module.mounts.sites.matrix]
roles = "*"
-- layouts/all.html --
{{ .Title }}|{{ .RelPermalink }}|Resources: {{ range .Resources }}{{ .RelPermalink }}|{{ end }}$
-- content/guest/_index.md --
---
title: "Guest"
---
-- content/member/_index.md --
---
title: "Member"
---
-- content/guest/_index._role_member_.md --
---
title: "Guest seen by member"
---
-- content/guest/myimage._role_member_.jpg --
MemberOnlyImage
-- content/guest/myimage.jpg --
SharedImage
`

	b := hugolib.Test(t, files)

	// The guest page ("/guest/") should have the "SharedImage" resource but NOT the "MemberOnlyImage" resource.
	b.AssertFileContent("public/guest/index.html",
		"Guest||Resources: /guest/myimage.jpg|$")

	// The guest page with _role_member_ in filename should appear only for member role.
	b.AssertFileContent("public/member/index.html",
		"Guest seen by member||Resources: /guest/myimage._role_member_.jpg|/guest/myimage.jpg|$")
}

