package sitesmatrix_test

import (
	"testing"

	"github.com/gohugoio/hugo/hugolib"
)

// TestFilenameRoleOverride verifies that a filename-based role identifier
// (e.g., _role_member_) overrides the mount configuration's role dimension.
func TestFilenameRoleOverride(t *testing.T) {
	t.Parallel()

	files := `
-- hugo.toml --
disableKinds = ["taxonomy", "term", "rss", "sitemap", "section"]
defaultContentRole = "guest"
defaultContentRoleInSubDir = true
[roles]
[roles.guest]
weight = 100
[roles.member]
weight = 200
[module]
[[module.mounts]]
source = 'content/guest'
target = 'content'
[module.mounts.sites.matrix]
roles = "*"
-- layouts/all.html --
{{ .Title }}|{{ .RelPermalink }}|Resources: {{ range .Resources }}{{ .RelPermalink }}|{{ end }}$
-- content/guest/_index.md --
---
title: "Guest"
---
-- content/guest/mytext.txt --
SharedText
`

	b := hugolib.Test(t, files)

	// The guest page should have the shared text.
	b.AssertFileContent("public/guest/index.html",
		"Guest|/guest/|Resources: /guest/mytext.txt|$")
}

