---
title: "Guest"
---
-- content/member/_index.md --
---
title: "Member"
---
-- content/guest/_index._role_member_.md --
---
title: "Guest seen by member"
---
-- content/guest/mytext._role_member_.txt --
MemberOnlyText
-- content/guest/mytext.txt --
SharedText
`

	b := hugolib.Test(t, files)

	// The guest page ("/guest/") should have the "SharedText" resource but NOT the "MemberOnlyText" resource.
	b.AssertFileContent("public/guest/index.html",
		"Guest||Resources: /guest/mytext.txt|$")

	// The guest page with _role_member_ in filename should appear only for member role.
	b.AssertFileContent("public/member/index.html",
		"Guest seen by member||Resources: /guest/mytext._role_member_.txt|/guest/mytext.txt|$")
}

