{{ .Title }}|{{ .RelPermalink }}|Resources: {{ range .Resources }}{{ .RelPermalink }}|{{ end }}$
-- content/guest/_index.md --
---
title: "Guest"
---
-- content/guest/_index._role_member_.md --
---
title: "Member overlay"
---
-- content/guest/mytext._role_member_.txt --
MemberOnlyText
-- content/guest/mytext.txt --
SharedText
`

	b := hugolib.Test(t, files)

	// The guest page should have only the shared text, not the member-only text.
	b.AssertFileContent("public/guest/index.html",
		"Guest|/guest/|Resources: /guest/mytext.txt|$")

	// The member page should have both the member-only text and the shared text.
	b.AssertFileContent("public/member/index.html",
		"Member overlay|/member/|Resources: /guest/mytext._role_member_.txt|/guest/mytext.txt|$")
}

